def _resolve_output_path(input_path: Path, output: Path | None, extension: str) -> Path:
    if output is None:
        return input_path.with_suffix(f".{extension}")
    if output.is_dir() or str(output).endswith(("/", "\\")):
        return output / f"{input_path.stem}.{extension}"
    return output

