def _collect_input_paths(paths: list[str], recursive: bool) -> list[Path]:
    collected: list[Path] = []
    for raw in paths:
        path = Path(raw)
        if path.is_dir():
            pattern = "**/*" if recursive else "*"
            for candidate in sorted(path.glob(pattern)):
                if candidate.is_file() and candidate.suffix.lower() in IMAGE_EXTENSIONS:
                    collected.append(candidate)
            continue
        if path.is_file():
            collected.append(path)
            continue
        raise FileNotFoundError(f"Input path not found: {raw}")
    if not collected:
        raise ValueError("No supported image files were found.")
    return collected

