def cmd_analyze(args: argparse.Namespace) -> int:
    input_path = Path(args.input)
    try:
        data, source_name = _read_input(input_path)
    except (FileNotFoundError, ValueError) as error:
        print(str(error), file=sys.stderr)
        return 1
    try:
        report = analyze_image(data, source_name)
    except ValueError as error:
        print(str(error), file=sys.stderr)
        return 1

    if args.json:
        print(json.dumps(report, indent=2))
        return 0

    print(report.get("summary", ""))
    print(f"Dimensions: {report['width']}×{report['height']} ({report.get('megapixels', 0)} MP)")
    print(f"Average RGB: {report.get('average_rgb')}")
    print(f"Average luminance: {report.get('average_luminance')}")
    if report.get("dominant_colors"):
        print("Dominant colors:")
        for color in report["dominant_colors"]:
            print(f"  {color['hex']} ({color['share'] * 100:.1f}%)")
    if report.get("decode_error"):
        print(f"Decode error: {report['decode_error']}", file=sys.stderr)
        return 1
    return 0

