def main(argv: list[str] | None = None) -> int:
    parser = build_parser()
    args = parser.parse_args(argv)
    if args.command in {"convert", "batch"}:
        if not args.preset and not args.format:
            print("Provide --format or --preset.", file=sys.stderr)
            return 2
        if args.format and parse_output_format(args.format) is None:
            print(f"Unsupported format: {args.format}", file=sys.stderr)
            return 2
    return int(args.handler(args))
